const body = $json.body || $json;
const id = String(body.id || `promo-ai-${Date.now()}`).trim();
const md = body.md || {};
const promo = body.promo || {};
const design = body.design || {};
const output = body.output || {};
const model = String(body.model || 'gpt-4o-mini').trim();

const requiredPromo = ['title', 'template', 'market', 'leadText', 'ctaLabel', 'ctaUrl', 'subline', 'termsText'];
const missingPromo = requiredPromo.filter((key) => !String(promo[key] || '').trim());
if (missingPromo.length) throw new Error(`Missing promo fields: ${missingPromo.join(', ')}`);
if (!md.brand) throw new Error('md.brand is required');
if (!md.designConcept && !md.designPromptContext) throw new Error('md.designConcept or md.designPromptContext is required');

return [{
  json: {
    id,
    model,
    md,
    promo,
    design,
    sourceDesign: body.sourceDesign || {},
    styleSource: body.styleSource || '',
    styleSourceLabel: body.styleSourceLabel || '',
    companyPreset: body.companyPreset || null,
    hasOverride: Boolean(body.hasOverride),
    output: {
      format: output.format || 'desktop_web_page',
      viewport: output.viewport || { width: 1440, minWidth: 1180 }
    }
  }
}];

const input = $json;
const concept = input.md.designConcept || {};
const conceptJson = concept.json || {};
const promptContext = input.md.designPromptContext || concept.promptContext || '';
const summary = input.md.summary || {};

const system = 'You are a senior promotional landing page designer and frontend engineer. Return valid JSON only.';
const user = `Create a desktop promotional web page using the selected design markdown analysis and promo inputs.

Return valid JSON only. Do not include markdown fences. Do not include explanations outside JSON.

Priority rules:
1. The promo input fields are the source of page content and must be visible in the page.
2. The selected MD design concept controls layout, visual mood, section rhythm, depth/effects, component style, shape/radius, and overall composition.
3. The final color/font style controls actual CSS color and typography values.
4. If styleSource is company_default, use company color/font values but still follow the MD's layout/effects/component concept.
5. If styleSource is design_md, use the MD-derived color/font values and MD concept together.
6. Legal/terms text must be visible, readable, and visually subordinate.
7. Generate for desktop first: 1440px viewport, minimum content width 1180px.
8. Do not use external JavaScript. Do not include script tags. Do not include inline event handlers.
9. CSS must be scoped under .promo-generated-page where practical.
10. Use Pretendard as the Korean/default web font unless the final style specifies another font.

Selected MD:
- brand: ${input.md.brand}
- slug: ${input.md.slug || ''}
- design concept summary: ${concept.summary || conceptJson.brandConcept || ''}
- design prompt context:\n${promptContext}
- concept JSON:\n${JSON.stringify(conceptJson, null, 2)}
- extracted categories: ${JSON.stringify(summary.categories || [])}
- extracted colors: ${JSON.stringify(summary.colors || [])}
- extracted fonts: ${JSON.stringify(summary.fonts || [])}

Promo inputs:\n${JSON.stringify(input.promo, null, 2)}

Final color/font style:\n${JSON.stringify(input.design, null, 2)}

Style source:
- styleSource: ${input.styleSource}
- styleSourceLabel: ${input.styleSourceLabel}
- companyPreset: ${input.companyPreset || ''}
- hasOverride: ${input.hasOverride}

Required JSON schema:
{
  "designIntent": "Short Korean explanation of how the MD concept was translated into the page.",
  "layoutSummary": "Short Korean summary of hero, sections, CTA, and legal layout.",
  "html": "HTML body content only. Start with <main class='promo-generated-page'> and do not include html/head/body tags.",
  "css": "CSS string. Include responsive desktop-safe CSS and @import for Pretendard if needed.",
  "qualityChecks": ["Concrete check that was satisfied."]
}`;

return [{
  json: {
    ...input,
    llmRequest: {
      model: input.model,
      messages: [
        { role: 'system', content: system },
        { role: 'user', content: user }
      ],
      temperature: 0.45,
      response_format: { type: 'json_object' }
    }
  }
}];

const input = $('Build Page Generation Prompt').item.json;
const response = $json;
const content = response.choices?.[0]?.message?.content || response.message?.content || response.content || response.text || response.output_text || '';
if (!content) throw new Error('LLM response content is empty');

let generated;
try {
  generated = typeof content === 'string'
    ? JSON.parse(content.replace(/^```json\s*/i, '').replace(/```$/i, '').trim())
    : content;
} catch (error) {
  throw new Error(`Failed to parse LLM JSON: ${error.message}`);
}

if (!generated.html || !generated.css) throw new Error('LLM JSON must include html and css');

const stripDangerous = (value) => String(value || '')
  .replace(/<script[\s\S]*?>[\s\S]*?<\/script>/gi, '')
  .replace(/\son[a-z]+\s*=\s*(['"]).*?\1/gi, '')
  .replace(/javascript:/gi, '');

const htmlBody = stripDangerous(generated.html);
const css = stripDangerous(generated.css);
const title = String(input.promo.title || 'Promo Page').replace(/[<>]/g, '');
const fullHtml = `<!doctype html><html lang='ko'><head><meta charset='utf-8'><meta name='viewport' content='width=device-width, initial-scale=1'><title>${title}</title><style>${css}</style></head><body>${htmlBody}</body></html>`;

const staticData = $getWorkflowStaticData('global');
staticData.pages = staticData.pages || {};
staticData.pages[input.id] = {
  html: fullHtml,
  payload: input,
  designIntent: generated.designIntent || '',
  layoutSummary: generated.layoutSummary || '',
  qualityChecks: generated.qualityChecks || [],
  createdAt: new Date().toISOString()
};

const headers = $('Generate AI Promo Page').item.json.headers || {};
const proto = headers['x-forwarded-proto'] || 'https';
const host = headers['x-forwarded-host'] || headers.host || '';
const pageUrl = host ? `${proto}://${host}/webhook/promo-ai-page-view/${encodeURIComponent(input.id)}` : `/webhook/promo-ai-page-view/${encodeURIComponent(input.id)}`;

return [{
  json: {
    ok: true,
    id: input.id,
    pageUrl,
    designIntent: generated.designIntent || '',
    layoutSummary: generated.layoutSummary || '',
    qualityChecks: generated.qualityChecks || [],
    payload: input
  }
}];

const id = $json.params?.id || $json.query?.id || '';
const staticData = $getWorkflowStaticData('global');
const page = staticData.pages?.[id];
const html = page?.html || `<!doctype html><html lang='ko'><head><meta charset='utf-8'><title>Promo page not found</title></head><body style='font-family:Arial,sans-serif;padding:40px'><h1>Promo page not found</h1><p>No generated page was stored for id: ${id}</p></body></html>`;
return [{ json: { html } }];
